// Obtém token Google e busca eventos do dia no Calendar
const tokenResp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const { access_token } = await tokenResp.json();

const agora = new Date();
const fimDia = new Date(agora);
fimDia.setHours(23, 59, 59, 999);

const url = `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${agora.toISOString()}&timeMax=${fimDia.toISOString()}&singleEvents=true&orderBy=startTime`;
const r = await fetch(url, { headers: { 'Authorization': `Bearer ${access_token}` } });
const data = await r.json();

const eventos = (data.items || []).map(e => {
  const inicio = e.start?.dateTime ? new Date(e.start.dateTime).toLocaleTimeString('pt-BR', {hour:'2-digit',minute:'2-digit'}) : 'dia todo';
  return `• ${inicio} — ${e.summary}`;
});

const hoje = agora.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long' });

const mensagem = eventos.length === 0
  ? `Bom dia. ${hoje.charAt(0).toUpperCase() + hoje.slice(1)} — nenhum evento agendado.`
  : `Bom dia. ${hoje.charAt(0).toUpperCase() + hoje.slice(1)}:\n${eventos.join('\n')}`;

return [{ json: { mensagem } }];
